def pagerank(graph, damping_factor=0.85, iterations=100, tolerance=1e-6):
    """
    Basitleştirilmiş PageRank algoritmasını uygular.

    Argümanlar:
        graph (dict): Web grafiği, anahtarlar sayfaları, değerler ise o sayfanın link verdiği sayfaların listesidir.
                      Örn: {'A': ['B', 'C'], 'B': ['C'], 'C': ['A']}
        damping_factor (float): Sönümleme faktörü (tipik olarak 0.85).
        iterations (int): Maksimum iterasyon sayısı.
        tolerance (float): PageRank değerlerinin yakınsama eşiği.

    Dönüş değeri:
        dict: Her sayfanın PageRank değerlerini içeren bir sözlük.
    """

    # 1. Tüm benzersiz sayfaları bul
    all_pages = set()
    for page, links in graph.items():
        all_pages.add(page)
        for link in links:
            all_pages.add(link)

    num_pages = len(all_pages)
    if num_pages == 0:
        return {}

    # 2. PageRank değerlerini başlat (1/N)
    ranks = {page: 1.0 / num_pages for page in all_pages}

    # 3. Her sayfanın dışa doğru bağlantı sayısını (out-degree) hesapla
    out_degrees = {page: len(graph.get(page, [])) for page in all_pages}

    # 4. PageRank iterasyonları
    for _ in range(iterations):
        new_ranks = {}

        # Askıda kalmış düğümlerin (hiçbir yere bağlantı vermeyen sayfalar) PageRank toplamını hesapla
        # Bu rank, tüm sayfalara eşit olarak dağıtılır.
        dangling_node_rank_sum = 0.0
        for page in all_pages:
            if out_degrees[page] == 0:
                dangling_node_rank_sum += ranks[page]

        for page_i in all_pages:
            # Temel rastgele gezinme payı
            rank_sum = (1.0 - damping_factor) / num_pages

            # Askıda kalmış düğümlerin payını ekle
            rank_sum += damping_factor * dangling_node_rank_sum / num_pages

            # page_i'ye bağlantı veren sayfalardan gelen payı ekle
            for page_j in all_pages:
                # page_j'nin page_i'ye bağlantı verip vermediğini kontrol et
                if page_j in graph and page_i in graph[page_j]:
                    # Yalnızca page_j askıda kalmış bir düğüm değilse (aksi halde payı zaten yukarıda hesaplandı)
                    if out_degrees[page_j] > 0:
                        rank_sum += damping_factor * (ranks[page_j] / out_degrees[page_j])

            new_ranks[page_i] = rank_sum

        # Yakınsamayı kontrol et
        max_diff = 0
        for page in all_pages:
            max_diff = max(max_diff, abs(new_ranks[page] - ranks[page]))

        ranks = new_ranks

        if max_diff < tolerance:
            break

    return ranks
